# Define similarity functions
def lcs_length(a, b):
    # longest common subsequence length (not substring)
    # dynamic programming O(len(a)*len(b))
    n, m = len(a), len(b)
    # initialize 2 rows to reduce memory
    prev = [0]*(m+1)
    for i in range(1, n+1):
        curr = [0]*(m+1)
        ai = a[i-1]
        for j in range(1, m+1):
            if ai == b[j-1]:
                curr[j] = prev[j-1] + 1
            else:
                curr[j] = prev[j] if prev[j] >= curr[j-1] else curr[j-1]
        prev = curr
    return prev[m]

def token_f1(a, b):
    # tokens are space-split normalized strings
    atoks = [t for t in a.split() if t]
    btoks = [t for t in b.split() if t]
    if not atoks or not btoks:
        return 0.0
    aset = {}
    for t in atoks:
        aset[t] = aset.get(t,0)+1
    overlap = 0
    bcounts = {}
    for t in btoks:
        bcounts[t] = bcounts.get(t,0)+1
    for t,c in aset.items():
        overlap += min(c, bcounts.get(t,0))
    prec = overlap/len(btoks)
    rec = overlap/len(atoks)
    if prec+rec == 0:
        return 0.0
    return 2*prec*rec/(prec+rec)

